import requests from '../requests_list';

const AdminScreen = () => {
  return (
    <section className="panel">
      <h1>Administracija zahteva</h1>
      <div className="admin-list">
        {requests.map((request) => (
          <article key={request.id}>
            <div>
              <strong>{request.type}</strong>
              <span>
                {request.book} - {request.user}
              </span>
            </div>
            <span className={`status ${request.status === 'Odobreno' ? 'approved' : 'waiting'}`}>
              {request.status}
            </span>
            <div>
              <button type="button">Odobri</button>
              <button type="button">Odbij</button>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
};

export default AdminScreen;
